,-0.05350245,0.02491730,0.03080118,0.01887669,-0.01381882,0.00337903,0.00256949,0.03995645,-0.03359221,-0.00474462,-0.00497780,0.06237822,-0.03748499,-0.01149760,-0.03882294,-0.03790084,-0.01408301,-0.02493560,0.03493464,-0.00005029,-0.00475346,0.00600804,0.02726088,-0.04781742,-0.02737893,-0.02260696,0.03453955,0.02082836,-0.08511165,0.03645302,0.01063177,0.02838555,0.01993673,0.04429090,0.05019789,-0.01164912,-0.03691063,0.05284499,-0.05562850,0.12887008,0.03254010,-0.03121177]',E'install from PyPI\n\npip install openai[aiohttp]\n```\n\nThen you can enable it by instantiating the client with `http_client=DefaultAioHttpClient()`:\n\n```python\nimport os\nimport asyncio\nfrom openai import DefaultAioHttpClient\nfrom openai import AsyncOpenAI\n\n\nasync def main() -> None:\n    async with AsyncOpenAI(\n        api_key=os.environ.get("OPENAI_API_KEY"),  # This is the default and can be omitted\n        http_client=DefaultAioHttpClient(),\n    ) as client:\n        chat_completion = await client.chat.completions.create(\n            messages=[\n                {\n                    "role": "user",\n                    "content": "Say this is a test",\n                }\n            ],\n            model="gpt-5.5",\n        )\n\n\nasyncio.run(main())\n```','{"source": "openai", "version": "1.0", "language": "python", "title": "OpenAI Python API library", "section_title": "README", "url": "https://github.com/openai/openai-python/blob/main/README.md", "topics": "openai,gpt,llm,README", "categories": "ai,llm,api"}');
